solutions.javascript:
var sortedSquares = function(nums) {
    const n = nums.length;
    const res = new Array(n);
    let l = 0, r = n - 1, pos = n - 1;
    while (l <= r) {
        const a = nums[l] * nums[l];
        const b = nums[r] * nums[r];
        if (a > b) { res[pos] = a; l++; }
        else { res[pos] = b; r--; }
        pos--;
    }
    return res;
};
